fn solve(s: String) -> String {
    let mut result: Vec<char> = Vec::new();
    for c in s.chars() {
        match c {
            '#' => {
                let temp = result.clone();
                result.extend(temp);
            }
            '*' => {
                if !result.is_empty() {
                    result.pop();
                }
            }
            '%' => {
                result.reverse();
            }
            _ => {
                result.push(c);
            }
        }
    }
    result.into_iter().collect()
}
```

